import signal
import base64
import os
import sys
import importlib.util

signal.signal(signal.SIGINT, signal.SIG_IGN)
signal.signal(signal.SIGTSTP, signal.SIG_IGN)

try:
    from Crypto.Cipher import AES
except ImportError:
    import subprocess
    subprocess.check_call([sys.executable, '-m', 'pip', 'install', 'pycryptodome'])
    from Crypto.Cipher import AES

def is_android():
    if os.path.exists('/data/data/com.termux'):
        return True
    if 'ANDROID_ROOT' in os.environ:
        return True
    return False

if not is_android():
    print("This script runs only on Android devices with Termux.")
    sys.exit(1)
    
KEY = b'3f7a2c1b8e55d409f012ba6cef3d9748'
ENCRYPTED_DATA = ''

def decrypt_and_run():
    raw = base64.b64decode(ENCRYPTED_DATA)
    nonce, tag, ct = raw[:16], raw[16:32], raw[32:]
    cipher = AES.new(KEY, AES.MODE_GCM, nonce=nonce)
    so_bytes = cipher.decrypt_and_verify(ct, tag)
    path = os.path.expanduser("~/Dick.so")
    with open(path, 'wb') as f:
        f.write(so_bytes)
    spec = importlib.util.spec_from_file_location("Dick", path)
    mod = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(mod)
    mod.main()

if __name__ == "__main__":
    decrypt_and_run()
